def cache_result(ttl=DEFAULT_CACHE_TTL, key_prefix=CACHE_PREFIX, bust_on=None):
    """
    Caching decorator for expensive database queries.
    
    Args:
        ttl: Time-to-live in seconds for the cached result.
        key_prefix: Prefix for the cache key in Redis.
        bust_on: Optional list of event names that should invalidate this cache.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build a unique cache key from function name and arguments
            cache_key = _build_cache_key(func, args, kwargs, key_prefix)

            # Try to get from cache
            cached = redis_pooled_client.get(cache_key)
            if cached is not None:
                result = json.loads(cached)
                # Add cache metadata
                if isinstance(result, dict):
                    result["_cache_hit"] = True
                return result

            # Execute the actual function (expensive query)
            result = func(*args, **kwargs)

            # Store in cache
            try:
                redis_pooled_client.set(cache_key, json.dumps(result), ex=ttl)
            except (TypeError, ValueError):
                # If result is not JSON serializable, skip caching
                pass

            if isinstance(result, dict):
                result["_cache_hit"] = False
            return result

        # Attach cache management methods to the wrapper
        wrapper.cache_clear = lambda *args, **kwargs: _clear_func_cache(
            func, args, kwargs, key_prefix
        )
        wrapper.cache_clear_all = lambda: _clear_all_func_cache(func, key_prefix)
        return wrapper

    return decorator


def _build_cache_key(func, args, kwargs, prefix):
    """Build a deterministic cache key from function signature and arguments."""
    key_parts = [func.__module__, func.__qualname__]
    
    # Include positional args (skip 'self' for methods)
    for arg in args:
        key_parts.append(str(arg))
    
    # Include keyword args sorted by key for determinism
    for k in sorted(kwargs.keys()):
        key_parts.append(f"{k}={kwargs[k]}")
    
    raw_key = ":".join(key_parts)
    hashed = hashlib.md5(raw_key.encode()).hexdigest()
    return f"{prefix}{func.__qualname__}:{hashed}"


def _clear_func_cache(func, args, kwargs, prefix):
    """Clear cache for specific function call."""
    cache_key = _build_cache_key(func, args, kwargs, prefix)
    return redis_pooled_client.delete(cache_key) > 0


def _clear_all_func_cache(func, prefix):
    """Clear all cached results for a function."""
    pattern = f"{prefix}{func.__qualname__}:*"
    keys = list(redis_pooled_client.scan_iter(match=pattern, count=100))
    if keys:
        return redis_pooled_client.delete(*keys)
    return 0


def invalidate_cache_pattern(pattern):
    """Invalidate all cache entries matching a pattern."""
    full_pattern = f"{CACHE_PREFIX}{pattern}"
    keys = list(redis_pooled_client.scan_iter(match=full_pattern, count=100))
    if keys:
        return redis_pooled_client.delete(*keys)
    return 0


