def rate_limit(max_requests=100, window_seconds=60):
    """Rate limiting decorator using Redis sliding window."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Use IP address as identifier
            client_ip = request.remote_addr or "unknown"
            rate_key = f"rate_limit:{func.__qualname__}:{client_ip}"
            
            current = redis_pooled_client.get(rate_key)
            if current is not None and int(current) >= max_requests:
                return jsonify({
                    "error": "Rate limit exceeded",
                    "retry_after": redis_pooled_client.ttl(rate_key),
                }), 429
            
            pipe = redis_pooled_client.pipeline()
            pipe.incr(rate_key)
            pipe.expire(rate_key, window_seconds)
            pipe.execute()
            
            return func(*args, **kwargs)
        return wrapper
    return decorator


